import React, { useState } from "react";
import API from "../services/api";
import "../styles/predictor.css";

function PlacementPredictor() {

  const [formData, setFormData] = useState({
    cgpa: "",
    dsa_score: "",
    aptitude_score: "",
    projects: "",
    internships: "",
    certifications: "",
    communication: "",
    skills_score: ""
  });

  const [result, setResult] = useState("");
  const [probability, setProbability] = useState("");

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const predictPlacement = async () => {
    try {

      const res = await API.post("/predict", formData);

      const prediction = res.data.prediction;
      const prob = res.data.probability;

      if (prediction === 1) {
        setResult("High Chance of Placement 🚀");
      } else {
        setResult("Low Chance of Placement ⚠️");
      }

      setProbability(`Prediction Confidence: ${prob}%`);

    } catch (error) {
      console.log(error);
      setResult("Prediction failed");
    }
  };

  return (
    <div className="predictor-container">

      <div className="predictor-card">

        <h1 className="predictor-title">
          AI Placement Predictor
        </h1>

        <input
          className="predictor-input"
          placeholder="CGPA"
          name="cgpa"
          onChange={handleChange}
        />

        <input
          className="predictor-input"
          placeholder="DSA Score"
          name="dsa_score"
          onChange={handleChange}
        />

        <input
          className="predictor-input"
          placeholder="Aptitude Score"
          name="aptitude_score"
          onChange={handleChange}
        />

        <input
          className="predictor-input"
          placeholder="Projects Completed"
          name="projects"
          onChange={handleChange}
        />

        <input
          className="predictor-input"
          placeholder="Internships"
          name="internships"
          onChange={handleChange}
        />

        <input
          className="predictor-input"
          placeholder="Certifications"
          name="certifications"
          onChange={handleChange}
        />

        <input
          className="predictor-input"
          placeholder="Communication Score"
          name="communication"
          onChange={handleChange}
        />

        <input
          className="predictor-input"
          placeholder="Technical Skills Score"
          name="skills_score"
          onChange={handleChange}
        />

        <button
          className="predictor-button"
          onClick={predictPlacement}
        >
          Predict Placement
        </button>

        {result && (
          <div className="predictor-result">
            {result}
            <br/>
            {probability}
          </div>
        )}

      </div>

    </div>
  );
}

export default PlacementPredictor;
